```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn       - 要执行的原始函数
 * @param {number}   delay    - 延迟时间(毫秒)
 * @param {Object}   options  - 可选配置
 * @param {boolean}  options.leading  - 是否在延迟开始前立即执行一次 (默认 false)
 * @param {boolean}  options.trailing - 是否在延迟结束后执行最后一次 (默认 true)
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;

  let timerId = null;
  let lastArgs = null;
  let leadingCalled = false;

  const invoke = (context) => {
    if (!trailing) return;
    fn.apply(context, lastArgs);
    leadingCalled = true;
  };

  const debounced = function (...args) {
    lastArgs = args;
    const context = this;

    // 如果当前没有等待中的 timer，且 leading 为 true
    if (timerId === null && leading && !leadingCalled) {
      fn.apply(context, args);
      leadingCalled = true;
    }

    // 清除上一次的计时器
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    // 设置新的计时器
    timerId = setTimeout(() => {
      invoke(context);
      timerId = null;
      leadingCalled = false; // 重置，让下一次 leading 可以再次触发
    }, delay);
  };

  /**
   * 取消防抖，尚未执行的调用将被取消
   */
  debounced.cancel = function () {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    leadingCalled = false;
    lastArgs = null;
  };

  /**
   * 立即执行并清空计时器
   */
  debounced.flush = function () {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
      fn.apply(this, lastArgs);
      leadingCalled = true;
    }
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 1. 基本用法 —— 搜索框输入结束 500ms 后才请求
const search = debounce((keyword) => {
  console.log('搜索:', keyword);
  // fetch(`/api/search?q=${keyword}`)
}, 500);

searchInput.addEventListener('input', (e) => search(e.target.value));

// 2. leading + trailing —— 按钮防连点，首次立即执行，停止点击后也执行一次
const save = debounce(() => {
  console.log('保存中...');
}, 1000, { leading: true, trailing: true });

saveBtn.addEventListener('click', save);

// 3. 取消防抖
const log = debounce((msg) => console.log(msg), 3000);
log('这条不会被执行');
log.cancel();

// 4. 立即冲刷
const send = debounce((msg) => console.log('发送:', msg), 5000);
send('hello');
send.flush(); // 立即执行，不等 5 秒
```

---

### 核心原理

| 概念 | 说明 |
|------|------|
| **延迟执行** | 每次调用都重置计时器，只有最后一次调用等待 `delay` 毫秒后才执行 |
| **leading** | 第一次调用时立即执行，后续高频调用被忽略，直到停止后才重置 |
| **trailing** | 停止高频调用后，延迟结束时执行最后一次调用（默认开启） |
| **cancel()** | 取消防抖，清除等待中的调用 |
| **flush()** | 立即执行当前等待中的调用 |

简单记忆：**debounce 把多次触发合并成一次执行**，适用于搜索联想、窗口 resize、按钮防连点等场景。

